/**
 * This object represents a parameter of the inline keyboard button used to
 * automatically authorize a user. Serves as a great replacement for the
 * Telegram Login Widget when the user is coming from Telegram. All the user
 * needs to do is tap/click a button and confirm that they want to log in:
 */
export const LoginUrl = Schema.Struct({
	/**
	 * An HTTPS URL to be opened with user authorization data added to the query
	 * string when the button is pressed. If the user refuses to provide
	 * authorization data, the original URL without information about the user will
	 * be opened. The data added is the same as described in Receiving
	 * authorization data.
	 * NOTE: You must always check the hash of the received data to verify the
	 * authentication and the integrity of the data as described in Checking
	 * authorization.
	 */
	url: Schema.String.pipe(
		Schema.annotate({
			description:
				"An HTTPS URL to be opened with user authorization data added to the query string when the button is pressed. If the user refuses to provide authorization data, the original URL without information about the user will be opened. The data added is the same as described in Receiving authorization data.\n\nNOTE: You must always check the hash of the received data to verify the authentication and the integrity of the data as described in Checking authorization.",
		}),
	),
	/**
	 * New text of the button in forwarded messages
	 */
	forward_text: Schema.optional(Schema.String).pipe(
		Schema.annotate({ description: "New text of the button in forwarded messages" }),
	),
	/**
	 * Username of a bot, which will be used for user authorization. See Setting up
	 * a bot for more details. If not specified, the current bot's username will be
	 * assumed. The url's domain must be the same as the domain linked with the
	 * bot. See Linking your domain to the bot for more details.
	 */
	bot_username: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"Username of a bot, which will be used for user authorization. See Setting up a bot for more details. If not specified, the current bot's username will be assumed. The url's domain must be the same as the domain linked with the bot. See Linking your domain to the bot for more details.",
		}),
	),
	/**
	 * Pass True to request the permission for your bot to send messages to the
	 * user
	 */
	request_write_access: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({ description: "Pass True to request the permission for your bot to send messages to the user" }),
	),
}).pipe(
	Schema.annotate({
		description:
			"This object represents a parameter of the inline keyboard button used to automatically authorize a user. Serves as a great replacement for the Telegram Login Widget when the user is coming from Telegram. All the user needs to do is tap/click a button and confirm that they want to log in:",
	}),
);
export type LoginUrl = typeof LoginUrl.Type;

