/**
 * This object represents one button of an inline keyboard. Exactly one of the
 * fields other than text, icon_custom_emoji_id, and style must be used to
 * specify the type of the button.
 */
export const InlineKeyboardButton = Schema.Struct({
	/**
	 * Label text on the button
	 */
	text: Schema.String.pipe(Schema.annotate({ description: "Label text on the button" })),
	/**
	 * Unique identifier of the custom emoji shown before the text of the button.
	 * Can only be used by bots that purchased additional usernames on Fragment or
	 * in the messages directly sent by the bot to private, group and supergroup
	 * chats if the owner of the bot has a Telegram Premium subscription.
	 */
	icon_custom_emoji_id: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"Unique identifier of the custom emoji shown before the text of the button. Can only be used by bots that purchased additional usernames on Fragment or in the messages directly sent by the bot to private, group and supergroup chats if the owner of the bot has a Telegram Premium subscription.",
		}),
	),
	/**
	 * Style of the button. Must be one of “danger” (red), “success” (green) or
	 * “primary” (blue). If omitted, then an app-specific style is used.
	 */
	style: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"Style of the button. Must be one of “danger” (red), “success” (green) or “primary” (blue). If omitted, then an app-specific style is used.",
		}),
	),
	/**
	 * HTTP or tg:// URL to be opened when the button is pressed. Links
	 * tg://user?id=<user_id> can be used to mention a user by their identifier
	 * without using a username, if this is allowed by their privacy settings.
	 */
	url: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"HTTP or tg:// URL to be opened when the button is pressed. Links tg://user?id=<user_id> can be used to mention a user by their identifier without using a username, if this is allowed by their privacy settings.",
		}),
	),
	/**
	 * Data to be sent in a callback query to the bot when the button is pressed,
	 * 1-64 bytes
	 */
	callback_data: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description: "Data to be sent in a callback query to the bot when the button is pressed, 1-64 bytes",
		}),
	),
	/**
	 * Description of the Web App that will be launched when the user presses the
	 * button. The Web App will be able to send an arbitrary message on behalf of
	 * the user using the method answerWebAppQuery. Available only in private chats
	 * between a user and the bot. Not supported for messages sent on behalf of a
	 * business account.
	 */
	web_app: Schema.optional(WebAppInfo).pipe(
		Schema.annotate({
			description:
				"Description of the Web App that will be launched when the user presses the button. The Web App will be able to send an arbitrary message on behalf of the user using the method answerWebAppQuery. Available only in private chats between a user and the bot. Not supported for messages sent on behalf of a business account.",
		}),
	),
	/**
	 * An HTTPS URL used to automatically authorize the user. Can be used as a
	 * replacement for the Telegram Login Widget.
	 */
	login_url: Schema.optional(LoginUrl).pipe(
		Schema.annotate({
			description:
				"An HTTPS URL used to automatically authorize the user. Can be used as a replacement for the Telegram Login Widget.",
		}),
	),
	/**
	 * If set, pressing the button will prompt the user to select one of their
	 * chats, open that chat and insert the bot's username and the specified inline
	 * query in the input field. May be empty, in which case just the bot's
	 * username will be inserted. Not supported for messages sent in channel direct
	 * messages chats and on behalf of a business account.
	 */
	switch_inline_query: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"If set, pressing the button will prompt the user to select one of their chats, open that chat and insert the bot's username and the specified inline query in the input field. May be empty, in which case just the bot's username will be inserted. Not supported for messages sent in channel direct messages chats and on behalf of a business account.",
		}),
	),
	/**
	 * If set, pressing the button will insert the bot's username and the specified
	 * inline query in the current chat's input field. May be empty, in which case
	 * only the bot's username will be inserted.
	 * This offers a quick way for the user to open your bot in inline mode in the
	 * same chat - good for selecting something from multiple options. Not
	 * supported in channels and for messages sent in channel direct messages chats
	 * and on behalf of a business account.
	 */
	switch_inline_query_current_chat: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"If set, pressing the button will insert the bot's username and the specified inline query in the current chat's input field. May be empty, in which case only the bot's username will be inserted.\n\nThis offers a quick way for the user to open your bot in inline mode in the same chat - good for selecting something from multiple options. Not supported in channels and for messages sent in channel direct messages chats and on behalf of a business account.",
		}),
	),
	/**
	 * If set, pressing the button will prompt the user to select one of their
	 * chats of the specified type, open that chat and insert the bot's username
	 * and the specified inline query in the input field. Not supported for
	 * messages sent in channel direct messages chats and on behalf of a business
	 * account.
	 */
	switch_inline_query_chosen_chat: Schema.optional(SwitchInlineQueryChosenChat).pipe(
		Schema.annotate({
			description:
				"If set, pressing the button will prompt the user to select one of their chats of the specified type, open that chat and insert the bot's username and the specified inline query in the input field. Not supported for messages sent in channel direct messages chats and on behalf of a business account.",
		}),
	),
	/**
	 * Description of the button that copies the specified text to the clipboard
	 */
	copy_text: Schema.optional(CopyTextButton).pipe(
		Schema.annotate({ description: "Description of the button that copies the specified text to the clipboard" }),
	),
	/**
	 * Description of the game that will be launched when the user presses the
	 * button.
	 * NOTE: This type of button must always be the first button in the first row.
	 */
	callback_game: Schema.optional(CallbackGame).pipe(
		Schema.annotate({
			description:
				"Description of the game that will be launched when the user presses the button.\n\nNOTE: This type of button must always be the first button in the first row.",
		}),
	),
	/**
	 * Specify True, to send a Pay button. Substrings “⭐” and “XTR” in the
	 * buttons's text will be replaced with a Telegram Star icon.
	 * NOTE: This type of button must always be the first button in the first row
	 * and can only be used in invoice messages.
	 */
	pay: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Specify True, to send a Pay button. Substrings “⭐” and “XTR” in the buttons's text will be replaced with a Telegram Star icon.\n\nNOTE: This type of button must always be the first button in the first row and can only be used in invoice messages.",
		}),
	),
}).pipe(
	Schema.annotate({
		description:
			"This object represents one button of an inline keyboard. Exactly one of the fields other than text, icon_custom_emoji_id, and style must be used to specify the type of the button.",
	}),
);
export type InlineKeyboardButton = typeof InlineKeyboardButton.Type;

