/**
 * This object represents one button of the reply keyboard. At most one of the
 * fields other than text, icon_custom_emoji_id, and style must be used to
 * specify the type of the button. For simple text buttons, String can be used
 * instead of this object to specify the button text.
 */
export const KeyboardButton = Schema.Struct({
	/**
	 * Text of the button. If none of the fields other than text,
	 * icon_custom_emoji_id, and style are used, it will be sent as a message when
	 * the button is pressed.
	 */
	text: Schema.String.pipe(
		Schema.annotate({
			description:
				"Text of the button. If none of the fields other than text, icon_custom_emoji_id, and style are used, it will be sent as a message when the button is pressed.",
		}),
	),
	/**
	 * Unique identifier of the custom emoji shown before the text of the button.
	 * Can only be used by bots that purchased additional usernames on Fragment or
	 * in the messages directly sent by the bot to private, group and supergroup
	 * chats if the owner of the bot has a Telegram Premium subscription.
	 */
	icon_custom_emoji_id: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"Unique identifier of the custom emoji shown before the text of the button. Can only be used by bots that purchased additional usernames on Fragment or in the messages directly sent by the bot to private, group and supergroup chats if the owner of the bot has a Telegram Premium subscription.",
		}),
	),
	/**
	 * Style of the button. Must be one of “danger” (red), “success” (green) or
	 * “primary” (blue). If omitted, then an app-specific style is used.
	 */
	style: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"Style of the button. Must be one of “danger” (red), “success” (green) or “primary” (blue). If omitted, then an app-specific style is used.",
		}),
	),
	/**
	 * If specified, pressing the button will open a list of suitable users.
	 * Identifiers of selected users will be sent to the bot in a “users_shared”
	 * service message. Available in private chats only.
	 */
	request_users: Schema.optional(KeyboardButtonRequestUsers).pipe(
		Schema.annotate({
			description:
				"If specified, pressing the button will open a list of suitable users. Identifiers of selected users will be sent to the bot in a “users_shared” service message. Available in private chats only.",
		}),
	),
	/**
	 * If specified, pressing the button will open a list of suitable chats.
	 * Tapping on a chat will send its identifier to the bot in a “chat_shared”
	 * service message. Available in private chats only.
	 */
	request_chat: Schema.optional(KeyboardButtonRequestChat).pipe(
		Schema.annotate({
			description:
				"If specified, pressing the button will open a list of suitable chats. Tapping on a chat will send its identifier to the bot in a “chat_shared” service message. Available in private chats only.",
		}),
	),
	/**
	 * If specified, pressing the button will ask the user to create and share a
	 * bot that will be managed by the current bot. Available for bots that enabled
	 * management of other bots in the @BotFather Mini App. Available in private
	 * chats only.
	 */
	request_managed_bot: Schema.optional(KeyboardButtonRequestManagedBot).pipe(
		Schema.annotate({
			description:
				"If specified, pressing the button will ask the user to create and share a bot that will be managed by the current bot. Available for bots that enabled management of other bots in the @BotFather Mini App. Available in private chats only.",
		}),
	),
	/**
	 * If True, the user's phone number will be sent as a contact when the button
	 * is pressed. Available in private chats only.
	 */
	request_contact: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"If True, the user's phone number will be sent as a contact when the button is pressed. Available in private chats only.",
		}),
	),
	/**
	 * If True, the user's current location will be sent when the button is
	 * pressed. Available in private chats only.
	 */
	request_location: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"If True, the user's current location will be sent when the button is pressed. Available in private chats only.",
		}),
	),
	/**
	 * If specified, the user will be asked to create a poll and send it to the bot
	 * when the button is pressed. Available in private chats only.
	 */
	request_poll: Schema.optional(KeyboardButtonPollType).pipe(
		Schema.annotate({
			description:
				"If specified, the user will be asked to create a poll and send it to the bot when the button is pressed. Available in private chats only.",
		}),
	),
	/**
	 * If specified, the described Web App will be launched when the button is
	 * pressed. The Web App will be able to send a “web_app_data” service message.
	 * Available in private chats only.
	 */
	web_app: Schema.optional(WebAppInfo).pipe(
		Schema.annotate({
			description:
				"If specified, the described Web App will be launched when the button is pressed. The Web App will be able to send a “web_app_data” service message. Available in private chats only.",
		}),
	),
}).pipe(
	Schema.annotate({
		description:
			"This object represents one button of the reply keyboard. At most one of the fields other than text, icon_custom_emoji_id, and style must be used to specify the type of the button. For simple text buttons, String can be used instead of this object to specify the button text.",
	}),
);
export type KeyboardButton = typeof KeyboardButton.Type;

