/**
 * This object represents a custom keyboard with reply options (see Introduction
 * to bots for details and examples). Not supported in channels and for messages
 * sent on behalf of a business account.
 */
export const ReplyKeyboardMarkup = Schema.Struct({
	/**
	 * Array of button rows, each represented by an Array of KeyboardButton objects
	 */
	keyboard: Schema.Array(Schema.Array(KeyboardButton)).pipe(
		Schema.annotate({ description: "Array of button rows, each represented by an Array of KeyboardButton objects" }),
	),
	/**
	 * Requests clients to always show the keyboard when the regular keyboard is
	 * hidden. Defaults to false, in which case the custom keyboard can be hidden
	 * and opened with a keyboard icon.
	 */
	is_persistent: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Requests clients to always show the keyboard when the regular keyboard is hidden. Defaults to false, in which case the custom keyboard can be hidden and opened with a keyboard icon.",
		}),
	),
	/**
	 * Requests clients to resize the keyboard vertically for optimal fit (e.g.,
	 * make the keyboard smaller if there are just two rows of buttons). Defaults
	 * to false, in which case the custom keyboard is always of the same height as
	 * the app's standard keyboard.
	 */
	resize_keyboard: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Requests clients to resize the keyboard vertically for optimal fit (e.g., make the keyboard smaller if there are just two rows of buttons). Defaults to false, in which case the custom keyboard is always of the same height as the app's standard keyboard.",
		}),
	),
	/**
	 * Requests clients to hide the keyboard as soon as it's been used. The
	 * keyboard will still be available, but clients will automatically display the
	 * usual letter-keyboard in the chat - the user can press a special button in
	 * the input field to see the custom keyboard again. Defaults to false.
	 */
	one_time_keyboard: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Requests clients to hide the keyboard as soon as it's been used. The keyboard will still be available, but clients will automatically display the usual letter-keyboard in the chat - the user can press a special button in the input field to see the custom keyboard again. Defaults to false.",
		}),
	),
	/**
	 * The placeholder to be shown in the input field when the keyboard is active;
	 * 1-64 characters
	 */
	input_field_placeholder: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description: "The placeholder to be shown in the input field when the keyboard is active; 1-64 characters",
		}),
	),
	/**
	 * Use this parameter if you want to show the keyboard to specific users only.
	 * Targets: 1) users that are @mentioned in the text of the Message object; 2)
	 * if the bot's message is a reply to a message in the same chat and forum
	 * topic, sender of the original message.
	 * Example: A user requests to change the bot's language, bot replies to the
	 * request with a keyboard to select the new language. Other users in the group
	 * don't see the keyboard.
	 */
	selective: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Use this parameter if you want to show the keyboard to specific users only. Targets: 1) users that are @mentioned in the text of the Message object; 2) if the bot's message is a reply to a message in the same chat and forum topic, sender of the original message.\n\nExample: A user requests to change the bot's language, bot replies to the request with a keyboard to select the new language. Other users in the group don't see the keyboard.",
		}),
	),
}).pipe(
	Schema.annotate({
		description:
			"This object represents a custom keyboard with reply options (see Introduction to bots for details and examples). Not supported in channels and for messages sent on behalf of a business account.",
	}),
);
export type ReplyKeyboardMarkup = typeof ReplyKeyboardMarkup.Type;

/**
 * Upon receiving a message with this object, Telegram clients will remove the
 * current custom keyboard and display the default letter-keyboard. By default,
 * custom keyboards are displayed until a new keyboard is sent by a bot. An
 * exception is made for one-time keyboards that are hidden immediately after
 * the user presses a button (see ReplyKeyboardMarkup). Not supported in
 * channels and for messages sent on behalf of a business account.
 */
export const ReplyKeyboardRemove = Schema.Struct({
	/**
	 * Requests clients to remove the custom keyboard (user will not be able to
	 * summon this keyboard; if you want to hide the keyboard from sight but keep
	 * it accessible, use one_time_keyboard in ReplyKeyboardMarkup)
	 */
	remove_keyboard: Schema.Literal(true).pipe(
		Schema.annotate({
			description:
				"Requests clients to remove the custom keyboard (user will not be able to summon this keyboard; if you want to hide the keyboard from sight but keep it accessible, use one_time_keyboard in ReplyKeyboardMarkup)",
		}),
	),
	/**
	 * Use this parameter if you want to remove the keyboard for specific users
	 * only. Targets: 1) users that are @mentioned in the text of the Message
	 * object; 2) if the bot's message is a reply to a message in the same chat and
	 * forum topic, sender of the original message.
	 * Example: A user votes in a poll, bot returns confirmation message in reply
	 * to the vote and removes the keyboard for that user, while still showing the
	 * keyboard with poll options to users who haven't voted yet.
	 */
	selective: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Use this parameter if you want to remove the keyboard for specific users only. Targets: 1) users that are @mentioned in the text of the Message object; 2) if the bot's message is a reply to a message in the same chat and forum topic, sender of the original message.\n\nExample: A user votes in a poll, bot returns confirmation message in reply to the vote and removes the keyboard for that user, while still showing the keyboard with poll options to users who haven't voted yet.",
		}),
	),
}).pipe(
	Schema.annotate({
		description:
			"Upon receiving a message with this object, Telegram clients will remove the current custom keyboard and display the default letter-keyboard. By default, custom keyboards are displayed until a new keyboard is sent by a bot. An exception is made for one-time keyboards that are hidden immediately after the user presses a button (see ReplyKeyboardMarkup). Not supported in channels and for messages sent on behalf of a business account.",
	}),
);
export type ReplyKeyboardRemove = typeof ReplyKeyboardRemove.Type;

/**
 * Describes reply parameters for the message that is being sent.
 */
export const ReplyParameters = Schema.Struct({
	/**
	 * Identifier of the message that will be replied to in the current chat, or in
	 * the chat chat_id if it is specified
	 */
	message_id: Schema.Int.pipe(
		Schema.annotate({
			description:
				"Identifier of the message that will be replied to in the current chat, or in the chat chat_id if it is specified",
		}),
	),
	/**
	 * If the message to be replied to is from a different chat, unique identifier
	 * for the chat or username of the bot, supergroup or channel in the format
	 * @username. Not supported for messages sent on behalf of a business account
	 * and messages from channel direct messages chats.
	 */
	chat_id: Schema.optional(Schema.Union([Schema.Int, Schema.String])).pipe(
		Schema.annotate({
			description:
				"If the message to be replied to is from a different chat, unique identifier for the chat or username of the bot, supergroup or channel in the format @username. Not supported for messages sent on behalf of a business account and messages from channel direct messages chats.",
		}),
	),
	/**
	 * Pass True if the message should be sent even if the specified message to be
	 * replied to is not found. Always False for replies in another chat or forum
	 * topic. Always True for messages sent on behalf of a business account.
	 */
	allow_sending_without_reply: Schema.optional(Schema.Boolean).pipe(
		Schema.annotate({
			description:
				"Pass True if the message should be sent even if the specified message to be replied to is not found. Always False for replies in another chat or forum topic. Always True for messages sent on behalf of a business account.",
		}),
	),
	/**
	 * Quoted part of the message to be replied to; 0-1024 characters after
	 * entities parsing. The quote must be an exact substring of the message to be
	 * replied to, including bold, italic, underline, strikethrough, spoiler,
	 * custom_emoji, and date_time entities. The message will fail to send if the
	 * quote isn't found in the original message.
	 */
	quote: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description:
				"Quoted part of the message to be replied to; 0-1024 characters after entities parsing. The quote must be an exact substring of the message to be replied to, including bold, italic, underline, strikethrough, spoiler, custom_emoji, and date_time entities. The message will fail to send if the quote isn't found in the original message.",
		}),
	),
	/**
	 * Mode for parsing entities in the quote. See formatting options for more
	 * details.
	 */
	quote_parse_mode: Schema.optional(Schema.String).pipe(
		Schema.annotate({
			description: "Mode for parsing entities in the quote. See formatting options for more details.",
		}),
	),
	/**
	 * A JSON-serialized list of special entities that appear in the quote. It can
	 * be specified instead of quote_parse_mode.
	 */
	quote_entities: Schema.optional(Schema.Array(MessageEntity)).pipe(
		Schema.annotate({
			description:
				"A JSON-serialized list of special entities that appear in the quote. It can be specified instead of quote_parse_mode.",
		}),
	),
	/**
	 * Position of the quote in the original message in UTF-16 code units
	 */
	quote_position: Schema.optional(Schema.Int).pipe(
		Schema.annotate({ description: "Position of the quote in the original message in UTF-16 code units" }),
	),
	/**
	 * Identifier of the specific checklist task to be replied to
	 */
	checklist_task_id: Schema.optional(Schema.Int).pipe(
		Schema.annotate({ description: "Identifier of the specific checklist task to be replied to" }),
	),
	/**
	 * Persistent identifier of the specific poll option to be replied to
	 */
	poll_option_id: Schema.optional(Schema.String).pipe(
		Schema.annotate({ description: "Persistent identifier of the specific poll option to be replied to" }),
	),
}).pipe(Schema.annotate({ description: "Describes reply parameters for the message that is being sent." }));
export type ReplyParameters = typeof ReplyParameters.Type;

/**
 * Describes why a request was unsuccessful.
 */
export const ResponseParameters = Schema.Struct({
	/**
	 * The group has been migrated to a supergroup with the specified identifier.
	 * This number may have more than 32 significant bits and some programming
	 * languages may have difficulty/silent defects in interpreting it. But it has
	 * at most 52 significant bits, so a signed 64-bit integer or double-precision
	 * float type are safe for storing this identifier.
	 */
	migrate_to_chat_id: Schema.optional(Schema.Int).pipe(
		Schema.annotate({
			description:
				"The group has been migrated to a supergroup with the specified identifier. This number may have more than 32 significant bits and some programming languages may have difficulty/silent defects in interpreting it. But it has at most 52 significant bits, so a signed 64-bit integer or double-precision float type are safe for storing this identifier.",
		}),
	),
	/**
	 * In case of exceeding flood control, the number of seconds left to wait
	 * before the request can be repeated
	 */
	retry_after: Schema.optional(Schema.Int).pipe(
		Schema.annotate({
			description:
				"In case of exceeding flood control, the number of seconds left to wait before the request can be repeated",
		}),
	),
}).pipe(Schema.annotate({ description: "Describes why a request was unsuccessful." }));
export type ResponseParameters = typeof ResponseParameters.Type;

