/**
 * Contains parameters of a post that is being suggested by the bot.
 */
export const SuggestedPostParameters = Schema.Struct({
	/**
	 * Proposed price for the post. If the field is omitted, then the post is
	 * unpaid.
	 */
	price: Schema.optional(SuggestedPostPrice).pipe(
		Schema.annotate({ description: "Proposed price for the post. If the field is omitted, then the post is unpaid." }),
	),
	/**
	 * Proposed send date of the post. If specified, then the date must be between
	 * 300 second and 2678400 seconds (30 days) in the future. If the field is
	 * omitted, then the post can be published at any time within 30 days at the
	 * sole discretion of the user who approves it.
	 */
	send_date: Schema.optional(Schema.Int).pipe(
		Schema.annotate({
			description:
				"Proposed send date of the post. If specified, then the date must be between 300 second and 2678400 seconds (30 days) in the future. If the field is omitted, then the post can be published at any time within 30 days at the sole discretion of the user who approves it.",
		}),
	),
}).pipe(Schema.annotate({ description: "Contains parameters of a post that is being suggested by the bot." }));
export type SuggestedPostParameters = typeof SuggestedPostParameters.Type;

